function getCookie(a){if(document.cookie.length>0){var b=document.cookie.indexOf(a+"=");if(b!=-1){b=b+a.length+1;end=document.cookie.indexOf(";",b);if(end==-1){end=document.cookie.length}return unescape(document.cookie.substring(b,end))}}return""}function setCookie(d,f,b,h,e,g){var c=new Date();c.setTime(c.getTime());if(b){b=b*1000*60*60*24}var a=new Date(c.getTime()+(b));document.cookie=d+"="+escape(f)+((b)?";expires="+a.toGMTString():"")+((h)?";path="+h:"")+((e)?";domain="+e:"")+((g)?";secure":"")}function handleCookie(d,g,a,h,b,f){stopPropagation(g);var e=document.getElementById(a);var c=false;if(isClassExpanded(e)){addCookieValue(b,h);removeCookieValue(f,h)}else{removeCookieValue(b,h);addCookieValue(f,h)}}function addCookieValue(c,e){var d=getCookie(c);var a="";if(d==null||d.length==0||d.indexOf('""')==0){a='"'+e+'"'}else{d=d.replace(/"/g,"");var b=d.split(",");if(arrayContains(b,e)){return false}a='"'+d+","+e+'"'}setCookie(c,a,0,"/");return true}function removeCookieValue(c,e){var d=getCookie(c);if(d==null||d.length<=0||d.indexOf('""')==0){return false}d=d.replace(/"/g,"");var b=d.split(",");b=removeValues(b,e);var a='"'+b.join(",")+'"';setCookie(c,a,0,"/");return true}function arrayContains(a,c){var b=0;for(var b=0;b<a.length;b++){if(a[b]==c){return true}}return false}function removeValues(a,c){var b=0;for(var b=0;b<a.length;b++){if(a[b]==c){a.splice(b,1)}}return a};